        "content": "#include<stdio.h>\n#include<stdlib.h>\n\ntypedef int ElemType;\n\ntypedef struct LNode{\n    ElemType data;\n    struct LNode *next;\n}LNode, *Linklist;\n\n// 初始化循环单链表\nbool InitList(LinkList &L){\n    L = (LNode *)malloc(sizeof(LNode));\n    if(L==NULL)\n        return false;\n    L->next = L; //头结点next指针指向头结点\n    return true;\n}\n\n// 判断循环单链表是否为空\nbool Empty(LinkList L){\n    if(L->next == L)\n        return true;\n    else\n        return false;\n}\n\n// 判断结点p是否为循环单链表的表尾结点\nbool isTail(LinkList L, LNode *p){\n    if(p->next == L)\n        return true;\n    else\n        return false;\n}\n\n// 插入操作\nbool ListInsert(LinkList &L, int i, ElemType e){\n    if(i<1) return false;\n    LNode *p = L;\n    int j=0;\n    while(p!=NULL && j<i-1){\n        p = p->next;\n        j++;\n        if(p == L) return false; // 防止无限循环\n    }\n    LNode *s = (LNode *)malloc(sizeof(LNode));\n    s->data = e;\n    s->next = p->next;\n    p->next = s;\n    return true;\n}\n\n// 打印循环单链表\nvoid PrintList(LinkList L){\n    if(Empty(L)) return;\n    LNode *p = L->next;\n    while(p != L){\n        printf(\"%d \", p->data);\n        p = p->next;\n    }\n    printf(\"\\n\");\n}\n\n// 循环双链表\ntypedef struct DNode{\n    ElemType data;\n    struct DNode *prior, *next;\n}DNode, *DLinklist;\n\n// 初始化循环双链表\nbool InitDLinkList(DLinklist &L){\n    L = (DNode *)malloc(sizeof(DNode));\n    if(L==NULL)\n        return false;\n    L->prior = L;\n    L->next = L;\n    return true;\n}\n\n// 判断循环双链表是否为空\nbool Empty(DLinklist L){\n    if(L->next == L)\n        return true;\n    else\n        return false;\n}\n\n// 判断结点p是否为循环双链表的表尾结点\nbool isTail(DLinklist L, DNode *p){\n    if(p->next == L)\n        return true;\n    else\n        return false;\n}\n\n// 插入操作\nbool InsertNextDNode(DNode *p, DNode *s){\n    s->next = p->next;\n    p->next->prior = s;\n    s->prior = p;\n    p->next = s;\n    return true;\n}\n\n// 删除操作\nbool DeleteNextDNode(DNode *p){\n    if(p==NULL) return false;\n    DNode *q = p->next;\n    if(q==NULL) return false;\n    p->next = q->next;\n    q->next->prior = p;\n    free(q);\n    return true;\n}\n\n// 打印循环双链表\nvoid PrintDList(DLinklist L){\n    if(Empty(L)) return;\n    DNode *p = L->next;\n    while(p != L){\n        printf(\"%d \", p->data);\n        p = p->next;\n    }\n    printf(\"\\n\");\n}\n\nint main(){\n    // 测试循环单链表\n    printf(\"=== 循环单链表 ===\\n\");\n    LinkList CL;\n    InitList(CL);\n    ListInsert(CL, 1, 10);\n    ListInsert(CL, 2, 20);\n    ListInsert(CL, 3, 30);\n    PrintList(CL);\n    \n    // 测试循环双链表\n    printf(\"\\n=== 循环双链表 ===\\n\");\n    DLinklist DCL;\n    InitDLinkList(DCL);\n    \n    DNode *s1 = (DNode *)malloc(sizeof(DNode));\n    s1->data = 100;\n    InsertNextDNode(DCL, s1);\n    \n    DNode *s2 = (DNode *)malloc(sizeof(DNode));\n    s2->data = 200;\n    InsertNextDNode(s1, s2);\n    \n    DNode *s3 = (DNode *)malloc(sizeof(DNode));\n    s3->data = 300;\n    InsertNextDNode(s2, s3);\n    \n    PrintDList(DCL);\n    \n    return 0;\n}",
