        "content": "#include<stdio.h>\n#include<stdlib.h>\n\ntypedef int ElemType;\n\ntypedef struct DNode{\n    ElemType data;\n    struct DNode *prior, *next;\n}DNode, *DLinklist;\n\n// 初始化双链表\nbool InitDLinkList(DLinklist &L){\n    L = (DNode *)malloc(sizeof(DNode));\n    if(L==NULL)\n        return false;\n    L->prior = NULL;\n    L->next = NULL;\n    return true;\n}\n\n// 判断双链表是否为空\nbool Empty(DLinklist L){\n    if(L->next == NULL)\n        return true;\n    else\n        return false;\n}\n\n// 后插操作\nbool InsertNextDNode(DNode *p, DNode *s){\n    if(p==NULL || s==NULL)\n        return false;\n    s->next = p->next;\n    if(p->next != NULL)\n        p->next->prior = s;\n    s->prior = p;\n    p->next = s;\n    return true;\n}\n\n// 删除p节点的后继节点\nbool DeletNextDNode(DNode *p){\n    if(p==NULL) return false;\n    DNode *q = p->next;\n    if(q==NULL) return false;\n    p->next = q->next;\n    if(q->next != NULL)\n        q->next->prior = p;\n    free(q);\n    return true;\n}\n\n// 销毁一个双链表\nbool DestoryList(DLinklist &L){\n    while(L->next != NULL){\n        DeletNextDNode(L);\n    }\n    free(L);\n    L=NULL;\n    return true;\n}\n\n// 打印双链表\nvoid PrintList(DLinklist L){\n    DNode *p = L->next;\n    while(p != NULL){\n        printf(\"%d \", p->data);\n        p = p->next;\n    }\n    printf(\"\\n\");\n}\n\n// 前向遍历\nvoid PrintListPrior(DLinklist L){\n    DNode *p = L;\n    while(p->next != NULL){\n        p = p->next;\n    }\n    while(p != L){\n        printf(\"%d \", p->data);\n        p = p->prior;\n    }\n    printf(\"\\n\");\n}\n\nint main(){\n    DLinklist L;\n    InitDLinkList(L);\n    \n    // 插入元素\n    DNode *s1 = (DNode *)malloc(sizeof(DNode));\n    s1->data = 10;\n    InsertNextDNode(L, s1);\n    \n    DNode *s2 = (DNode *)malloc(sizeof(DNode));\n    s2->data = 20;\n    InsertNextDNode(s1, s2);\n    \n    DNode *s3 = (DNode *)malloc(sizeof(DNode));\n    s3->data = 30;\n    InsertNextDNode(s2, s3);\n    \n    printf(\"双链表：\");\n    PrintList(L);\n    \n    // 测试删除\n    DeletNextDNode(s1);\n    printf(\"删除后：\");\n    PrintList(L);\n    \n    // 测试前向遍历\n    printf(\"前向遍历：\");\n    PrintListPrior(L);\n    \n    // 销毁链表\n    DestoryList(L);\n    \n    return 0;\n}",
