        "content": "#include<stdio.h>\n#include<stdlib.h>\n\ntypedef int ElemType;\n\ntypedef struct LNode{\n    ElemType data;\n    struct LNode *next;\n}LNode, *LinkList;\n\n// 初始化空的单链表（不带头节点）\nbool InitList(LinkList &L){\n    L = NULL; //空表，暂时还没有任何结点\n    return true;\n}\n\n// 初始化单链表（带头结点）\nbool InitListWithHead(LinkList &L){\n    L = (LNode*) malloc(sizeof(LNode));  //头指针指向的结点——分配一个头结点（不存储数据）\n    if (L == NULL)          //内存不足，分配失败\n        return false;\n    L->next = NULL;       //头结点之后暂时还没有结点\n    return true;\n}\n\n// 判断单链表是否为空（不带头节点）\nbool Empty(LinkList L){\n    return (L==NULL);\n}\n\n// 判断单链表是否为空（带头结点）\nbool EmptyWithHead(LinkList L){\n    if (L->next == NULL)\n        return true;\n    else\n        return false;\n}\n\n// 按位序插入（带头结点）\nbool ListInsert(LinkList &L, int i, ElemType e){\n    if(i<1)\n        return false;\n    LNode *p;       //指针p指向当前扫描到的结点     \n    int j=0;        //当前p指向的是第几个结点\n    p = L;          //L指向头结点，头结点是第0个结点（不存数据）\n    while(p!=NULL && j<i-1){     //如果i>lengh, p最后会等于NULL\n        p = p->next;             //p指向下一个结点\n        j++;\n    }\n    if (p==NULL)                 //如果p指针知道最后再往后就是NULL\n        return false;\n    LNode *s = (LNode *)malloc(sizeof(LNode)); //申请一个结点\n    s->data = e;\n    s->next = p->next;\n    p->next = s;                 //将结点s连到p后,后两步千万不能颠倒\n    return true;\n}\n\n// 后插操作\nbool InsertNextNode(LNode *p, ElemType e){\n    if(p==NULL){\n        return false;\n    }\n    LNode *s = (LNode *)malloc(sizeof(LNode));\n    if(s==NULL)\n        return false;\n    s->data = e;          //用结点s保存数据元素e     \n    s->next = p->next;\n    p->next = s;          //将结点s连到p之后\n    return true;\n}\n\n// 前插操作\nbool InsertPriorNode(LNode *p, ElemType e){\n    if(p==NULL)\n        return false;\n    LNode *s = (LNode *)malloc(sizeof(LNode));\n    if(s==NULL) //内存分配失败\n        return false;\n    s->next = p->next;\n    p->next = s;       //新结点s连到p之后\n    s->data = p->data; //将p中元素复制到s\n    p->data = e;       //p中元素覆盖为e\n    return true;\n}\n\n// 按位序删除节点\nbool ListDelete(LinkList &L, int i, ElemType &e){\n    if(i<1) return false;\n    LNode *p;       //指针p指向当前扫描到的结点     \n    int j=0;        //当前p指向的是第几个结点\n    p = L;          //L指向头结点，头结点是第0个结点（不存数据）\n    while(p!=NULL && j<i-1){     //如果i>lengh, p最后会等于NULL\n        p = p->next;             //p指向下一个结点\n        j++;\n    }\n    if(p==NULL) return false;\n    if(p->next == NULL) //第i-1个结点之后已无其他结点\n        return false;\n    LNode *q = p->next;         //令q指向被删除的结点\n    e = q->data;                //用e返回被删除元素的值\n    p->next = q->next;          //将*q结点从链中“断开”\n    free(q);                     //释放结点的存储空间\n    return true;\n}\n\n// 指定结点的删除\nbool DeleteNode(LNode *p){\n    if(p==NULL)\n        return false;\n    LNode *q = p->next;      //令q指向*p的后继结点\n    p->data = p->next->data; //让p和后继结点交换数据域\n    p->next = q->next;       //将*q结点从链中“断开”\n    free(q);\n    return true;\n}\n\n// 按位查找\nLNode* GetElem(LinkList L, int i){\n    if(i<0) return NULL;\n    LNode *p;               //指针p指向当前扫描到的结点\n    int j=0;                //当前p指向的是第几个结点\n    p = L;                  //L指向头结点,头结点是第0个结点(不存数据)\n    while(p!=NULL && j<i){  //循环找到第i个结点\n        p = p->next;\n        j++;\n    }\n    return p;               //返回p指针指向的值\n}\n\n// 按值查找\nLNode* LocateElem(LinkList L, ElemType e){\n    LNode *p = L->next;    //p指向第一个结点\n    while(p!=NULL && p->data != e){\n        p = p->next;\n    }\n    return p;           //找到后返回该结点指针，否则返回NULL\n}\n\n// 求单链表的长度\nint Length(LinkList L){\n    int len=0;       //统计表长\n    LNode *p = L;\n    while(p->next != NULL){\n        p = p->next;\n        len++;\n    }\n    return len;\n}\n\n// 尾插法建立单链表\nLinkList List_TailInsert(LinkList &L){\n    int x;            //设ElemType为整型int      \n    L = (LinkList)malloc(sizeof(LNode));     //建立头结点(初始化空表)\n    LNode *s, *r = L;                        //r为表尾指针\n    printf(\"请输入数据，输入9999结束：\");\n    scanf(\"%d\", &x);                         //输入要插入的结点的值\n    while(x!=9999){                          //输入9999表示结束\n        s = (LNode *)malloc(sizeof(LNode));\n        s->data = x;\n        r->next = s;\n        r = s;                               //r指针指向新的表尾结点\n        scanf(\"%d\", &x);\n    }\n    r->next = NULL;                          //尾结点指针置空\n    return L;\n}\n\n// 头插法建立单链表\nLinkList List_HeadInsert(LinkList &L){\n    LNode *s;\n    int x;\n    L = (LinkList)malloc(sizeof(LNode));     //建立头结点\n    L->next = NULL;                          //初始为空链表,这步不能少！\n    printf(\"请输入数据，输入9999结束：\");\n    scanf(\"%d\", &x);                         //输入要插入的结点的值\n    while(x!=9999){                          //输入9999表结束\n        s = (LNode *)malloc(sizeof(LNode));  //创建新结点\n        s->data = x;\n        s->next = L->next;\n        L->next = s;                         //将新结点插入表中，L为头指针\n        scanf(\"%d\", &x);\n    }\n    return L;\n}\n\n// 链表的逆置\nLinkList ReverseList(LinkList L){\n    LNode *p, *q;\n    p = L->next;     //p指针指向第一个结点\n    L->next = NULL;  //头结点指向NULL\n    while (p != NULL){\n        q = p;\n        p = p->next;\n        q->next = L->next;\n        L->next = q;\n    }\n    return L;\n}\n\n// 打印链表\nvoid PrintList(LinkList L){\n    LNode *p = L->next;\n    while(p != NULL){\n        printf(\"%d \", p->data);\n        p = p->next;\n    }\n    printf(\"\\n\");\n}\n\nint main(){\n    LinkList L;\n    InitListWithHead(L);\n    \n    // 测试插入操作\n    ListInsert(L, 1, 10);\n    ListInsert(L, 2, 20);\n    ListInsert(L, 3, 30);\n    printf(\"插入后链表：\");\n    PrintList(L);\n    \n    // 测试删除操作\n    int e;\n    ListDelete(L, 2, e);\n    printf(\"删除后链表：\");\n    PrintList(L);\n    \n    // 测试查找操作\n    LNode *p = GetElem(L, 1);\n    printf(\"第1个元素：%d\\n\", p->data);\n    \n    p = LocateElem(L, 30);\n    printf(\"值为30的元素：%d\\n\", p->data);\n    \n    // 测试链表长度\n    printf(\"链表长度：%d\\n\", Length(L));\n    \n    // 测试链表逆置\n    ReverseList(L);\n    printf(\"逆置后链表：\");\n    PrintList(L);\n    \n    return 0;\n}",
