        "content": "#include<stdio.h>\n#define MaxSize 10\n\ntypedef int ElemType;\n\ntypedef struct{\n    ElemType data;\n    int next;\n}SLinkList[MaxSize];\n\n// 初始化静态链表\nvoid InitList(SLinkList &L){\n    for(int i=0; i<MaxSize-1; i++){\n        L[i].next = i+1;\n    }\n    L[MaxSize-1].next = 0; // 尾节点的next指向0\n}\n\n// 分配空闲节点\nint Malloc_SL(SLinkList &L){\n    int i = L[0].next;\n    if(L[0].next != 0){\n        L[0].next = L[i].next;\n    }\n    return i;\n}\n\n// 回收节点\nvoid Free_SL(SLinkList &L, int k){\n    L[k].next = L[0].next;\n    L[0].next = k;\n}\n\n// 插入操作\nvoid ListInsert(SLinkList &L, int i, ElemType e){\n    int j = Malloc_SL(L);\n    if(j){ // 分配成功\n        L[j].data = e;\n        int p = MaxSize-1;\n        for(int l=1; l<i; l++){\n            p = L[p].next;\n        }\n        L[j].next = L[p].next;\n        L[p].next = j;\n    }\n}\n\n// 删除操作\nvoid ListDelete(SLinkList &L, int i, ElemType &e){\n    int p = MaxSize-1;\n    for(int l=1; l<i; l++){\n        p = L[p].next;\n    }\n    int q = L[p].next;\n    e = L[q].data;\n    L[p].next = L[q].next;\n    Free_SL(L, q);\n}\n\n// 打印静态链表\nvoid PrintList(SLinkList L){\n    int p = L[MaxSize-1].next;\n    while(p != 0){\n        printf(\"%d \", L[p].data);\n        p = L[p].next;\n    }\n    printf(\"\\n\");\n}\n\nint main(){\n    SLinkList L;\n    InitList(L);\n    \n    // 插入元素\n    ListInsert(L, 1, 10);\n    ListInsert(L, 2, 20);\n    ListInsert(L, 3, 30);\n    printf(\"静态链表：\");\n    PrintList(L);\n    \n    // 删除元素\n    int e;\n    ListDelete(L, 2, e);\n    printf(\"删除后：\");\n    PrintList(L);\n    printf(\"删除的元素：%d\\n\", e);\n    \n    return 0;\n}",
