        "content": "#include<stdio.h>\n#include<stdlib.h>\n\ntypedef int ElemType;\n\ntypedef struct Linknode{\n    ElemType data;\n    struct Linknode *next;\n}Linknode,*LiStack;\n\n// 初始化栈\nbool InitStack(LiStack &L){\n    L = (Linknode *)malloc(sizeof(Linknode));\n    if(L == NULL)\n        return false;\n    L->next = NULL;\n    return true;\n}\n\n// 判断栈是否为空\nbool isEmpty(LiStack L){\n    if(L->next == NULL)\n        return true;\n    else\n        return false;\n}\n\n// 入栈\nbool pushStack(LiStack &L, ElemType x){\n    Linknode *s = (Linknode *)malloc(sizeof(Linknode));\n    if(s == NULL)\n        return false;\n    s->data = x;\n    s->next = L->next;\n    L->next = s;\n    return true;\n}\n\n// 出栈\nbool popStack(LiStack &L, ElemType &x){\n    if(L->next == NULL)\n        return false;\n    Linknode *s = L->next;\n    x = s->data;\n    L->next = s->next;\n    free(s);\n    return true;\n}\n\n// 获取栈顶元素\nbool GetTop(LiStack L, ElemType &x){\n    if(L->next == NULL)\n        return false;\n    x = L->next->data;\n    return true;\n}\n\n// 打印栈\nvoid PrintStack(LiStack L){\n    Linknode *p = L->next;\n    while(p != NULL){\n        printf(\"%d \", p->data);\n        p = p->next;\n    }\n    printf(\"\\n\");\n}\n\nint main(){\n    LiStack L;\n    InitStack(L);\n    \n    pushStack(L, 10);\n    pushStack(L, 20);\n    pushStack(L, 30);\n    printf(\"栈元素：\");\n    PrintStack(L);\n    \n    int x;\n    popStack(L, x);\n    printf(\"出栈元素：%d\\n\", x);\n    printf(\"栈元素：\");\n    PrintStack(L);\n    \n    GetTop(L, x);\n    printf(\"栈顶元素：%d\\n\", x);\n    \n    return 0;\n}",
