        "content": "#include<stdio.h>\n#define MaxSize 10\n\ntypedef int ElemType;\n\ntypedef struct{\n    ElemType data[MaxSize];\n    int front, rear;\n}SqQueue;\n\n// 初始化队列\nvoid InitQueue(SqQueue &Q){\n    Q.rear = Q.front = 0;\n}\n\n// 判断队列是否为空\nbool QueueEmpty(SqQueue Q){\n    if(Q.rear == Q.front)\n        return true;\n    else\n        return false;\n}\n\n// 入队\nbool EnQueue(SqQueue &Q, ElemType x){\n    if((Q.rear+1)%MaxSize == Q.front)\n        return false;\n    Q.data[Q.rear] = x;\n    Q.rear = (Q.rear+1)%MaxSize;\n    return true;\n}\n\n// 出队\nbool DeQueue(SqQueue &Q, ElemType &x){\n    if(Q.rear == Q.front)\n        return false;\n    x = Q.data[Q.front];\n    Q.front = (Q.front+1)%MaxSize;\n    return true;\n}\n\n// 获取队头元素\nbool GetHead(SqQueue Q, ElemType &x){\n    if(Q.rear == Q.front)\n        return false;\n    x = Q.data[Q.front];\n    return true;\n}\n\n// 打印队列\nvoid PrintQueue(SqQueue Q){\n    int i = Q.front;\n    while(i != Q.rear){\n        printf(\"%d \", Q.data[i]);\n        i = (i+1)%MaxSize;\n    }\n    printf(\"\\n\");\n}\n\n// 队列长度\nint QueueLength(SqQueue Q){\n    return (Q.rear - Q.front + MaxSize) % MaxSize;\n}\n\n// 带size的队列\ntypedef struct{\n    ElemType data[MaxSize];\n    int front, rear;\n    int size;\n}SqQueueWithSize;\n\n// 初始化队列\nvoid InitQueueWithSize(SqQueueWithSize &Q){\n    Q.rear = Q.front = 0;\n    Q.size = 0;\n}\n\n// 判断队列是否为空\nbool QueueEmptyWithSize(SqQueueWithSize Q){\n    if(Q.size == 0)\n        return true;\n    else\n        return false;\n}\n\n// 入队\nbool EnQueueWithSize(SqQueueWithSize &Q, ElemType x){\n    if(Q.size == MaxSize)\n        return false;\n    Q.data[Q.rear] = x;\n    Q.rear = (Q.rear+1)%MaxSize;\n    Q.size++;\n    return true;\n}\n\n// 出队\nbool DeQueueWithSize(SqQueueWithSize &Q, ElemType &x){\n    if(Q.size == 0)\n        return false;\n    x = Q.data[Q.front];\n    Q.front = (Q.front+1)%MaxSize;\n    Q.size--;\n    return true;\n}\n\nint main(){\n    // 测试循环队列\n    printf(\"=== 循环队列 ===\\n\");\n    SqQueue Q;\n    InitQueue(Q);\n    \n    EnQueue(Q, 10);\n    EnQueue(Q, 20);\n    EnQueue(Q, 30);\n    printf(\"队列元素：\");\n    PrintQueue(Q);\n    printf(\"队列长度：%d\\n\", QueueLength(Q));\n    \n    int x;\n    DeQueue(Q, x);\n    printf(\"出队元素：%d\\n\", x);\n    printf(\"队列元素：\");\n    PrintQueue(Q);\n    \n    GetHead(Q, x);\n    printf(\"队头元素：%d\\n\", x);\n    \n    // 测试带size的队列\n    printf(\"\\n=== 带size的队列 ===\\n\");\n    SqQueueWithSize QS;\n    InitQueueWithSize(QS);\n    \n    EnQueueWithSize(QS, 100);\n    EnQueueWithSize(QS, 200);\n    EnQueueWithSize(QS, 300);\n    \n    DeQueueWithSize(QS, x);\n    printf(\"出队元素：%d\\n\", x);\n    \n    return 0;\n}",
