        "path": "chapter3/seq_stack.c",
        "content": "#include<stdio.h>\n#define MaxSize 10\n\ntypedef int ElemType;\n\ntypedef struct{\n    ElemType data[MaxSize];\n    int top;\n}SqStack;\n\n// 初始化栈\nvoid InitStack(SqStack &S){\n    S.top = -1;\n}\n\n// 判断栈是否为空\nbool StackEmpty(SqStack S){\n    if(S.top == -1)\n        return true;\n    else\n        return false;\n}\n\n// 入栈\nbool Push(SqStack &S, ElemType x){\n    if(S.top == MaxSize - 1)\n        return false;\n    S.data[++S.top] = x;\n    return true;\n}\n\n// 出栈\nbool Pop(SqStack &S, ElemType &x){\n    if(S.top == -1)\n        return false;\n    x = S.data[S.top--];\n    return true;\n}\n\n// 读取栈顶元素\nbool GetTop(SqStack S, ElemType &x){\n    if(S.top == -1)\n        return false;\n    x = S.data[S.top];\n    return true;\n}\n\n// 打印栈\nvoid PrintStack(SqStack S){\n    for(int i=S.top; i>=0; i--){\n        printf(\"%d \", S.data[i]);\n    }\n    printf(\"\\n\");\n}\n\n// 共享栈\ntypedef struct{\n    ElemType data[MaxSize];\n    int top0;\n    int top1;\n}ShStack;\n\n// 初始化共享栈\nvoid InitShStack(ShStack &S){\n    S.top0 = -1;\n    S.top1 = MaxSize;\n}\n\n// 0号栈入栈\nbool Push0(ShStack &S, ElemType x){\n    if(S.top0 + 1 == S.top1)\n        return false;\n    S.data[++S.top0] = x;\n    return true;\n}\n\n// 1号栈入栈\nbool Push1(ShStack &S, ElemType x){\n    if(S.top0 + 1 == S.top1)\n        return false;\n    S.data[--S.top1] = x;\n    return true;\n}\n\n// 0号栈出栈\nbool Pop0(ShStack &S, ElemType &x){\n    if(S.top0 == -1)\n        return false;\n    x = S.data[S.top0--];\n    return true;\n}\n\n// 1号栈出栈\nbool Pop1(ShStack &S, ElemType &x){\n    if(S.top1 == MaxSize)\n        return false;\n    x = S.data[S.top1++];\n    return true;\n}\n\nint main(){\n    // 测试顺序栈\n    printf(\"=== 顺序栈 ===\\n\");\n    SqStack S;\n    InitStack(S);\n    \n    Push(S, 10);\n    Push(S, 20);\n    Push(S, 30);\n    printf(\"栈元素：\");\n    PrintStack(S);\n    \n    int x;\n    Pop(S, x);\n    printf(\"出栈元素：%d\\n\", x);\n    printf(\"栈元素：\");\n    PrintStack(S);\n    \n    GetTop(S, x);\n    printf(\"栈顶元素：%d\\n\", x);\n    \n    // 测试共享栈\n    printf(\"\\n=== 共享栈 ===\\n\");\n    ShStack ShS;\n    InitShStack(ShS);\n    \n    Push0(ShS, 100);\n    Push0(ShS, 200);\n    Push1(ShS, 300);\n    Push1(ShS, 400);\n    \n    Pop0(ShS, x);\n    printf(\"0号栈出栈：%d\\n\", x);\n    \n    Pop1(ShS, x);\n    printf(\"1号栈出栈：%d\\n\", x);\n    \n    return 0;\n}",
        "lines": 139,
