        "content": "#include<stdio.h>\n#include<stdlib.h>\n#define MaxSize 100\n\ntypedef int ElemType;\n\n// 打印数组\nvoid PrintArray(int a[], int n){\n    for(int i=0; i<n; i++){\n        printf(\"%d \", a[i]);\n    }\n    printf(\"\\n\");\n}\n\n// 直接插入排序\nvoid InsertSort(int a[], int n){\n    for(int i=1; i<n; i++){\n        if(a[i] < a[i-1]){\n            int temp = a[i];\n            int j = i-1;\n            while(j>=0 && a[j]>temp){\n                a[j+1] = a[j];\n                j--;\n            }\n            a[j+1] = temp;\n        }\n    }\n}\n\n// 折半插入排序\nvoid BinaryInsertSort(int a[], int n){\n    for(int i=1; i<n; i++){\n        int temp = a[i];\n        int low = 0, high = i-1;\n        while(low <= high){\n            int mid = (low + high)/2;\n            if(a[mid] > temp){\n                high = mid - 1;\n            }else{\n                low = mid + 1;\n            }\n        }\n        for(int j=i-1; j>=high+1; j--){\n            a[j+1] = a[j];\n        }\n        a[high+1] = temp;\n    }\n}\n\n// 希尔排序\nvoid ShellSort(int a[], int n){\n    for(int d=n/2; d>=1; d=d/2){\n        for(int i=d; i<n; i++){\n            if(a[i] < a[i-d]){\n                int temp = a[i];\n                int j = i-d;\n                while(j>=0 && a[j]>temp){\n                    a[j+d] = a[j];\n                    j = j-d;\n                }\n                a[j+d] = temp;\n            }\n        }\n    }\n}\n\n// 冒泡排序\nvoid BubbleSort(int a[], int n){\n    for(int i=0; i<n-1; i++){\n        bool flag = false;\n        for(int j=0; j<n-i-1; j++){\n            if(a[j] > a[j+1]){\n                int temp = a[j];\n                a[j] = a[j+1];\n                a[j+1] = temp;\n                flag = true;\n            }\n        }\n        if(!flag) break;\n    }\n}\n\n// 快速排序\nint Partition(int a[], int low, int high){\n    int pivot = a[low];\n    while(low < high){\n        while(low < high && a[high] >= pivot) high--;\n        a[low] = a[high];\n        while(low < high && a[low] <= pivot) low++;\n        a[high] = a[low];\n    }\n    a[low] = pivot;\n    return low;\n}\n\nvoid QuickSort(int a[], int low, int high){\n    if(low < high){\n        int pivotpos = Partition(a, low, high);\n        QuickSort(a, low, pivotpos-1);\n        QuickSort(a, pivotpos+1, high);\n    }\n}\n\n// 简单选择排序\nvoid SelectSort(int a[], int n){\n    for(int i=0; i<n-1; i++){\n        int min = i;\n        for(int j=i+1; j<n; j++){\n            if(a[j] < a[min]){\n                min = j;\n            }\n        }\n        if(min != i){\n            int temp = a[i];\n            a[i] = a[min];\n            a[min] = temp;\n        }\n    }\n}\n\n// 堆排序\nvoid HeapAdjust(int a[], int k, int len){\n    a[0] = a[k];\n    for(int i=2*k; i<=len; i*=2){\n        if(i<len && a[i]<a[i+1]){\n            i++;\n        }\n        if(a[0] >= a[i]){\n            break;\n        }else{\n            a[k] = a[i];\n            k = i;\n        }\n    }\n    a[k] = a[0];\n}\n\nvoid BuildMaxHeap(int a[], int len){\n    for(int i=len/2; i>0; i--){\n        HeapAdjust(a, i, len);\n    }\n}\n\nvoid HeapSort(int a[], int len){\n    BuildMaxHeap(a, len);\n    for(int i=len; i>1; i--){\n        int temp = a[1];\n        a[1] = a[i];\n        a[i] = temp;\n        HeapAdjust(a, 1, i-1);\n    }\n}\n\n// 归并排序\nvoid Merge(int a[], int low, int mid, int high){\n    int b[MaxSize];\n    for(int i=low; i<=high; i++){\n        b[i] = a[i];\n    }\n    int i=low, j=mid+1, k=low;\n    while(i<=mid && j<=high){\n        if(b[i] <= b[j]){\n            a[k++] = b[i++];\n        }else{\n            a[k++] = b[j++];\n        }\n    }\n    while(i<=mid){\n        a[k++] = b[i++];\n    }\n    while(j<=high){\n        a[k++] = b[j++];\n    }\n}\n\nvoid MergeSort(int a[], int low, int high){\n    if(low < high){\n        int mid = (low + high)/2;\n        MergeSort(a, low, mid);\n        MergeSort(a, mid+1, high);\n        Merge(a, low, mid, high);\n    }\n}\n\n// 基数排序\nint GetMax(int a[], int n){\n    int max = a[0];\n    for(int i=1; i<n; i++){\n        if(a[i] > max){\n            max = a[i];\n        }\n    }\n    return max;\n}\n\nint GetDigit(int x, int d){\n    int div = 1;\n    for(int i=1; i<d; i++){\n        div *= 10;\n    }\n    return (x / div) % 10;\n}\n\nvoid RadixSort(int a[], int n){\n    int max = GetMax(a, n);\n    int digits = 0;\n    while(max != 0){\n        max /= 10;\n        digits++;\n    }\n    \n    int bucket[10][MaxSize];\n    int count[10];\n    \n    for(int d=1; d<=digits; d++){\n        for(int i=0; i<10; i++){\n            count[i] = 0;\n        }\n        \n        for(int i=0; i<n; i++){\n            int digit = GetDigit(a[i], d);\n            bucket[digit][count[digit]++] = a[i];\n        }\n        \n        int k = 0;\n        for(int i=0; i<10; i++){\n            for(int j=0; j<count[i]; j++){\n                a[k++] = bucket[i][j];\n            }\n        }\n    }\n}\n\nint main(){\n    int a[] = {49, 38, 65, 97, 76, 13, 27, 49};\n    int n = sizeof(a)/sizeof(a[0]);\n    \n    // 测试直接插入排序\n    printf(\"=== 直接插入排序 ===\\n\");\n    int b[MaxSize];\n    memcpy(b, a, n*sizeof(int));\n    InsertSort(b, n);\n    PrintArray(b, n);\n    \n    // 测试折半插入排序\n    printf(\"=== 折半插入排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    BinaryInsertSort(b, n);\n    PrintArray(b, n);\n    \n    // 测试希尔排序\n    printf(\"=== 希尔排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    ShellSort(b, n);\n    PrintArray(b, n);\n    \n    // 测试冒泡排序\n    printf(\"=== 冒泡排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    BubbleSort(b, n);\n    PrintArray(b, n);\n    \n    // 测试快速排序\n    printf(\"=== 快速排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    QuickSort(b, 0, n-1);\n    PrintArray(b, n);\n    \n    // 测试简单选择排序\n    printf(\"=== 简单选择排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    SelectSort(b, n);\n    PrintArray(b, n);\n    \n    // 测试堆排序\n    printf(\"=== 堆排序 ===\\n\");\n    int c[MaxSize];\n    for(int i=0; i<n; i++){\n        c[i+1] = a[i];\n    }\n    HeapSort(c, n);\n    for(int i=1; i<=n; i++){\n        printf(\"%d \", c[i]);\n    }\n    printf(\"\\n\");\n    \n    // 测试归并排序\n    printf(\"=== 归并排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    MergeSort(b, 0, n-1);\n    PrintArray(b, n);\n    \n    // 测试基数排序\n    printf(\"=== 基数排序 ===\\n\");\n    memcpy(b, a, n*sizeof(int));\n    RadixSort(b, n);\n    PrintArray(b, n);\n    \n    return 0;\n}",
